function getStartPagesJsonData(ids){var restoreUserSelect=document.documentElement.style.webkitUserSelect;document.documentElement.style.webkitUserSelect="auto";const cfis=isScrollMode()?getRowStartPages():getColumnStartPages();document.documentElement.style.webkitUserSelect=restoreUserSelect;return JSON.stringify(cfis)}function getColumnStartPages(){const pages=[];const clientWidth=getClientWidth();if(clientWidth>0){const scrollWidth=document.scrollingElement.scrollWidth;let prevCfi=null;let left=0;while(left<scrollWidth){const position=left/scrollWidth;document.scrollingElement.scrollLeft=left;let cfi=null;const range=document.caretRangeFromPoint(0,0);if(range){cfi=rangeToEpubCfi(range)}if(cfi){prevCfi=cfi}else{cfi=prevCfi??""}pages.push({cfi:cfi,position:position});left=left+clientWidth}}return pages}function getRowStartPages(){const pages=[];const clientHeight=getClientHeight();if(clientHeight>0){const contentScrollHeight=getContentScrollHeight();const scrollHeight=document.scrollingElement.scrollHeight;let prevCfi=null;let top=0;while(top<contentScrollHeight){const position=top/scrollHeight;document.scrollingElement.scrollTop=top;let cfi=null;const range=document.caretRangeFromPoint(0,0);if(range){cfi=rangeToEpubCfi(range)}if(cfi){prevCfi=cfi}else{cfi=prevCfi??""}pages.push({cfi:cfi,position:position});top=top+clientHeight}}return pages}function getTextRangeForIdsJsonData(ids){return JSON.stringify(Object.fromEntries(getTextRangeForIds(ids)))}function getTextRangeForIds(ids){const map=new Map;if(ids){ids.forEach(id=>{const cfi=getTextRangeForId(id);if(cfi){map.set(id,cfi)}})}return map}function getTextRangeForId(id){const element=document.getElementById(id);if(element){const range=document.createRange();range.selectNodeContents(element);const cfi=rangeToEpubCfi(range);const position=getTextStartPositionFromRange(range);return{cfi:cfi??"",position:position}}return null}function pageIndexOfId(id){return pageIndexUsingGetClientRects(document.getElementById(id))}function pageIndexOfCfi(cfi){return pageIndexUsingGetClientRects(epubCfiToRange(cfi))}function pageIndexUsingGetClientRects(object){if(object&&typeof object.getClientRects==="function"){const rects=object.getClientRects();if(rects.length>0){return pageIndexOfRect(rects[0])}}return 0}function pageIndexOfRect(rect){let index=0;if(rect){if(isScrollMode()){const clientHeight=getClientHeight();if(clientHeight>0){index=(document.scrollingElement.scrollTop+rect.top)/clientHeight}}else{const clientWidth=getClientWidth();if(clientWidth>0){index=(document.scrollingElement.scrollLeft+rect.left)/clientWidth}}}return Math.max(0,Math.floor(index))}